import React, { useState } from "react";
import {
  LayoutGrid,
  Wallet,
  Folder,
  Network,
  Lightbulb,
  FileText,
  Truck,
  Pencil,
  Eye,
  Trash2,
  X,
  Check,
  Plus,
} from "lucide-react";

// ---------------------------------------------------------------------------
// Config: one entry per side button. Each master has its own field set and
// its own seed rows, but they all render through the same list+form template
// so the whole panel reads as one system instead of seven bespoke screens.
// ---------------------------------------------------------------------------
const MASTERS = [
  {
    key: "schemeType",
    label: "Scheme type",
    icon: LayoutGrid,
    listTitle: "Scheme type list",
    fields: [
      { key: "name", label: "Scheme type", placeholder: "Enter scheme type", required: true },
      { key: "localName", label: "Scheme type (local)", placeholder: "Enter scheme type in local language" },
    ],
    seed: [
      { id: 1, name: "Approval", localName: "" },
      { id: 2, name: "Permission", localName: "" },
      { id: 3, name: "Subsidy", localName: "" },
    ],
  },
  {
    key: "subsidyType",
    label: "Subsidy type",
    icon: Wallet,
    listTitle: "Subsidy type list",
    fields: [
      { key: "name", label: "Subsidy type", placeholder: "Enter subsidy type", required: true },
      { key: "localName", label: "Subsidy type (local)", placeholder: "Enter subsidy type in local language" },
    ],
    seed: [
      { id: 1, name: "Capital subsidy", localName: "" },
      { id: 2, name: "Interest subsidy", localName: "" },
    ],
  },
  {
    key: "schemeCategory",
    label: "Scheme category",
    icon: Folder,
    listTitle: "Scheme category list",
    fields: [
      { key: "name", label: "Category name", placeholder: "Enter category name", required: true },
      { key: "code", label: "Category code", placeholder: "Enter category code" },
    ],
    seed: [
      { id: 1, name: "Agriculture", code: "AGR" },
      { id: 2, name: "Renewable energy", code: "REN" },
    ],
  },
  {
    key: "schemeSubCategory",
    label: "Scheme sub-category",
    icon: Network,
    listTitle: "Scheme sub-category list",
    fields: [
      { key: "name", label: "Sub-category name", placeholder: "Enter sub-category name", required: true },
      { key: "parent", label: "Parent category", placeholder: "Enter parent category" },
    ],
    seed: [{ id: 1, name: "Solar rooftop", parent: "Renewable energy" }],
  },
  {
    key: "schemeTechnology",
    label: "Scheme technology",
    icon: Lightbulb,
    listTitle: "Scheme technology list",
    fields: [
      { key: "name", label: "Technology name", placeholder: "Enter technology name", required: true },
      { key: "description", label: "Description", placeholder: "Enter a short description" },
    ],
    seed: [
      { id: 1, name: "Photovoltaic", description: "" },
      { id: 2, name: "Wind turbine", description: "" },
    ],
  },
  {
    key: "documents",
    label: "Documents",
    icon: FileText,
    listTitle: "Document list",
    fields: [
      { key: "name", label: "Document name", placeholder: "Enter document name", required: true },
      { key: "type", label: "Document type", placeholder: "e.g. Identity proof" },
    ],
    seed: [
      { id: 1, name: "Aadhaar card", type: "Identity proof" },
      { id: 2, name: "Land record", type: "Ownership proof" },
    ],
  },
  {
    key: "vendors",
    label: "Vendors",
    icon: Truck,
    listTitle: "Vendor list",
    fields: [
      { key: "name", label: "Vendor name", placeholder: "Enter vendor name", required: true },
      { key: "contact", label: "Contact number", placeholder: "Enter contact number" },
    ],
    seed: [{ id: 1, name: "Sunrise Traders", contact: "" }],
  },
];

const emptyForm = (fields) =>
  Object.fromEntries(fields.map((f) => [f.key, ""]));

export default function SchemeAdminPanel() {
  const [activeKey, setActiveKey] = useState(MASTERS[0].key);
  const [dataByKey, setDataByKey] = useState(() =>
    Object.fromEntries(MASTERS.map((m) => [m.key, m.seed]))
  );
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState(() => emptyForm(MASTERS[0].fields));

  const active = MASTERS.find((m) => m.key === activeKey);
  const rows = dataByKey[activeKey];

  function switchMaster(key) {
    const master = MASTERS.find((m) => m.key === key);
    setActiveKey(key);
    setEditingId(null);
    setForm(emptyForm(master.fields));
  }

  function handleFieldChange(key, value) {
    setForm((prev) => ({ ...prev, [key]: value }));
  }

  function handleSave() {
    const requiredField = active.fields.find((f) => f.required);
    if (requiredField && !form[requiredField.key]?.trim()) return;

    setDataByKey((prev) => {
      const list = prev[activeKey];
      if (editingId != null) {
        return {
          ...prev,
          [activeKey]: list.map((row) =>
            row.id === editingId ? { ...row, ...form } : row
          ),
        };
      }
      const nextId = list.length ? Math.max(...list.map((r) => r.id)) + 1 : 1;
      return { ...prev, [activeKey]: [...list, { id: nextId, ...form }] };
    });

    setEditingId(null);
    setForm(emptyForm(active.fields));
  }

  function handleCancel() {
    setEditingId(null);
    setForm(emptyForm(active.fields));
  }

  function handleEdit(row) {
    setEditingId(row.id);
    setForm(
      Object.fromEntries(active.fields.map((f) => [f.key, row[f.key] ?? ""]))
    );
  }

  function handleDelete(id) {
    setDataByKey((prev) => ({
      ...prev,
      [activeKey]: prev[activeKey].filter((row) => row.id !== id),
    }));
    if (editingId === id) handleCancel();
  }

  return (
    <div
      style={{
        "--ink-900": "#1a1f2b",
        "--ink-600": "#5b6472",
        "--ink-400": "#8b93a1",
        "--line": "#e6e8ec",
        "--line-soft": "#eef0f3",
        "--accent": "#4f5bd5",
        "--accent-50": "#eef0fd",
        "--accent-600": "#4048b8",
        "--danger": "#e0473e",
        "--danger-50": "#fdecea",
        fontFamily:
          '-apple-system,BlinkMacSystemFont,"Segoe UI",Inter,Roboto,sans-serif',
        color: "var(--ink-900)",
        maxWidth: 1400,
        margin: "0 auto",
        background: "#fff",
        border: "1px solid var(--line)",
        borderRadius: 14,
        overflow: "hidden",
        boxShadow: "0 1px 2px rgba(20,22,30,0.04)",
      }}
    >
      {/* Frame header */}
      <div
        style={{
          padding: "18px 24px",
          borderBottom: "1px solid var(--line)",
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <h1 style={{ fontSize: 16, fontWeight: 600, margin: 0 }}>
          Scheme master data
        </h1>
        <div style={{ fontSize: 13, color: "var(--ink-400)" }}>
          Settings / Masters /{" "}
          <span style={{ color: "var(--ink-600)", fontWeight: 500 }}>
            {active.label}
          </span>
        </div>
      </div>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "240px 1px 1fr 1px 1fr",
        }}
      >
        {/* ---- LEFT NAV: 7 buttons ---- */}
        <nav style={{ padding: "20px 14px", background: "#fbfbfc" }}>
          <div
            style={{
              fontSize: 11,
              fontWeight: 600,
              letterSpacing: "0.04em",
              textTransform: "uppercase",
              color: "var(--ink-400)",
              padding: "0 10px 10px",
            }}
          >
            Add master entry
          </div>
          {MASTERS.map((m) => {
            const Icon = m.icon;
            const isActive = m.key === activeKey;
            return (
              <button
                key={m.key}
                onClick={() => switchMaster(m.key)}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                  width: "100%",
                  padding: "9px 10px",
                  border: "none",
                  borderLeft: isActive
                    ? "2px solid var(--accent)"
                    : "2px solid transparent",
                  background: isActive ? "var(--accent-50)" : "transparent",
                  borderRadius: isActive ? "0 8px 8px 0" : 8,
                  fontSize: 13.5,
                  fontWeight: 500,
                  color: isActive ? "var(--accent-600)" : "var(--ink-600)",
                  textAlign: "left",
                  cursor: "pointer",
                  marginBottom: 2,
                }}
              >
                <Icon
                  size={17}
                  color={isActive ? "var(--accent-600)" : "var(--ink-400)"}
                />
                {m.label}
              </button>
            );
          })}
        </nav>

        <div style={{ background: "var(--line-soft)" }} />

        {/* ---- LIST PANEL ---- */}
        <div style={{ display: "flex", flexDirection: "column" }}>
          <div style={{ padding: "16px 22px", borderBottom: "1px solid var(--line)" }}>
            <h2 style={{ fontSize: 14.5, fontWeight: 600, margin: "0 0 2px" }}>
              {active.listTitle}
            </h2>
            <p style={{ fontSize: 12.5, color: "var(--ink-400)", margin: 0 }}>
              {rows.length} {rows.length === 1 ? "entry" : "entries"}
            </p>
          </div>
          <div style={{ padding: "18px 22px", flex: 1 }}>
            <table style={{ width: "100%", borderCollapse: "collapse" }}>
              <thead>
                <tr>
                  <th style={thStyle}></th>
                  <th style={thStyle}>{active.fields[0].label}</th>
                  <th style={{ ...thStyle, textAlign: "right" }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((row, i) => (
                  <tr key={row.id}>
                    <td style={{ ...tdStyle, color: "var(--ink-400)", width: 28 }}>
                      {i + 1}
                    </td>
                    <td style={tdStyle}>{row.name}</td>
                    <td style={{ ...tdStyle, textAlign: "right", whiteSpace: "nowrap" }}>
                      <IconBtn onClick={() => handleEdit(row)} variant="accent" label="Edit">
                        <Pencil size={15} />
                      </IconBtn>
                      <IconBtn onClick={() => alert(JSON.stringify(row, null, 2))} label="View">
                        <Eye size={15} />
                      </IconBtn>
                      <IconBtn onClick={() => handleDelete(row.id)} variant="danger" label="Delete">
                        <Trash2 size={15} />
                      </IconBtn>
                    </td>
                  </tr>
                ))}
                {rows.length === 0 && (
                  <tr>
                    <td colSpan={3} style={{ ...tdStyle, color: "var(--ink-400)", textAlign: "center", padding: "24px 0" }}>
                      No entries yet. Add one using the form on the right.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        <div style={{ background: "var(--line-soft)" }} />

        {/* ---- FORM PANEL ---- */}
        <div style={{ display: "flex", flexDirection: "column" }}>
          <div style={{ padding: "16px 22px", borderBottom: "1px solid var(--line)" }}>
            <h2 style={{ fontSize: 14.5, fontWeight: 600, margin: "0 0 2px" }}>
              {editingId != null ? `Edit ${active.label.toLowerCase()}` : `Add ${active.label.toLowerCase()}`}
            </h2>
            <p style={{ fontSize: 12.5, color: "var(--ink-400)", margin: 0 }}>
              Fill in the details below and save.
            </p>
          </div>
          <div style={{ padding: "18px 22px", flex: 1 }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "16px 18px" }}>
              {active.fields.map((f) => (
                <div key={f.key} style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                  <label style={{ fontSize: 12.5, fontWeight: 500, color: "var(--ink-600)" }}>
                    {f.label}
                    {f.required && <span style={{ color: "var(--danger)", marginLeft: 2 }}>*</span>}
                  </label>
                  <input
                    type="text"
                    placeholder={f.placeholder}
                    value={form[f.key] ?? ""}
                    onChange={(e) => handleFieldChange(f.key, e.target.value)}
                    style={inputStyle}
                    onFocus={(e) => {
                      e.target.style.borderColor = "var(--accent)";
                      e.target.style.boxShadow = "0 0 0 3px var(--accent-50)";
                    }}
                    onBlur={(e) => {
                      e.target.style.borderColor = "var(--line)";
                      e.target.style.boxShadow = "none";
                    }}
                  />
                </div>
              ))}
            </div>

            <div
              style={{
                marginTop: 22,
                paddingTop: 16,
                borderTop: "1px solid var(--line)",
                display: "flex",
                justifyContent: "flex-end",
                gap: 8,
              }}
            >
              <button onClick={handleCancel} style={btnStyle}>
                <X size={14} /> Cancel
              </button>
              <button
                onClick={handleSave}
                style={{ ...btnStyle, background: "var(--accent)", borderColor: "var(--accent)", color: "#fff" }}
              >
                {editingId != null ? <Check size={14} /> : <Plus size={14} />}
                {editingId != null ? "Update" : "Save"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function IconBtn({ onClick, children, variant, label }) {
  const [hover, setHover] = useState(false);
  const colors = {
    default: { fg: "var(--ink-400)", bg: "var(--line-soft)", hoverFg: "var(--ink-900)" },
    accent: { fg: "var(--ink-400)", bg: "var(--accent-50)", hoverFg: "var(--accent-600)" },
    danger: { fg: "var(--ink-400)", bg: "var(--danger-50)", hoverFg: "var(--danger)" },
  }[variant || "default"];

  return (
    <button
      aria-label={label}
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{
        width: 28,
        height: 28,
        borderRadius: 7,
        border: "none",
        background: hover ? colors.bg : "transparent",
        color: hover ? colors.hoverFg : colors.fg,
        display: "inline-flex",
        alignItems: "center",
        justifyContent: "center",
        cursor: "pointer",
        marginLeft: 4,
      }}
    >
      {children}
    </button>
  );
}

const thStyle = {
  textAlign: "left",
  fontSize: 11,
  fontWeight: 600,
  letterSpacing: "0.03em",
  textTransform: "uppercase",
  color: "var(--ink-400)",
  padding: "0 10px 10px",
  borderBottom: "1px solid var(--line)",
};

const tdStyle = {
  padding: "12px 10px",
  fontSize: 13.5,
  borderBottom: "1px solid var(--line-soft)",
  color: "var(--ink-900)",
};

const inputStyle = {
  height: 36,
  border: "1px solid var(--line)",
  borderRadius: 8,
  padding: "0 12px",
  fontSize: 13.5,
  color: "var(--ink-900)",
  background: "#fcfcfd",
  outline: "none",
};

const btnStyle = {
  height: 34,
  padding: "0 16px",
  borderRadius: 8,
  fontSize: 13,
  fontWeight: 600,
  border: "1px solid var(--line)",
  background: "#fff",
  color: "var(--ink-600)",
  display: "inline-flex",
  alignItems: "center",
  gap: 6,
  cursor: "pointer",
};
